5	import PublicHeader from "@/components/PublicHeader";
6	import { db } from "@/lib/db";
7	import { getFounder } from "@/lib/auth";
8	import {
9	  MIN_PUBLISHABLE_SAMPLE,
10	  describeConfidenceBand,
11	  formatSlopeCi,
12	  type MethodTrackRecordRow,
13	} from "@/lib/methodTrackRecord";
