19	function decimalToNumber(value: unknown): number | null {
20	  if (value === null || value === undefined) return null;
21	  if (typeof value === "number") return Number.isFinite(value) ? value : null;
22	  if (typeof value === "string") {
23	    const n = Number(value);
24	    return Number.isFinite(n) ? n : null;
25	  }
26	  if (typeof value === "object" && "toNumber" in (value as object)) {
27	    try {
28	      const n = (value as { toNumber: () => number }).toNumber();
29	      return Number.isFinite(n) ? n : null;
30	    } catch {
31	      return null;
32	    }
33	  }
34	  return null;
35	}
36	
37	/**
38	 * Public track-record page for a method, addressed by `[method]` (the
39	 * method `name` field — versions roll up). The publish gate is a hard
40	 * filter: rows below `MIN_PUBLISHABLE_SAMPLE` are excluded, and if no
41	 * row clears the threshold the page returns 404 rather than rendering
42	 * a "no data" placeholder. The intent is that the page exists when —
43	 * and only when — there are enough resolved predictions linked to the
44	 * method to publish a record honestly.
45	 *
46	 * Multi-tenant note: track records are materialized per-org. The public
47	 * page picks the largest-sample row per (version, domain) across all
48	 * orgs that have published a track record for this method. The
49	 * organization id is not exposed in the public surface — the reader
50	 * sees only the method's empirical record.
51	 */
52	export default async function PublicMethodTrackRecordPage({
53	  params,
54	}: {
55	  params: Promise<{ method: string }>;
56	}) {
57	  const { method } = await params;
58	  const methodName = decodeURIComponent(method);
59	
60	  const rawRows = await db.methodTrackRecord.findMany({
61	    where: { methodName },
62	    orderBy: [{ methodVersion: "desc" }, { sampleSize: "desc" }],
63	  });
64	
65	  const rows: MethodTrackRecordRow[] = rawRows.map((r) => ({
