5	export type PublicationMethodologyProfile = {
6	  patternType: string;
7	  title: string;
8	  summary: string;
9	  reasoningMoves: string[];
10	  transferTargets: string[];
11	  assumptions: string[];
12	  failureModes: string[];
13	  evidenceAnchors: { sentenceIndex?: number; sourceTitle?: string }[];
14	  confidence: number;
15	};
16	
17	export type PublicationMethodology = {
18	  schema: "theseus.methodology.v1";
19	  reviewerNarrative: string;
20	  profiles: PublicationMethodologyProfile[];
21	};
22	
23	type MethodologyProfileRow = {
24	  id: string;
25	  conclusionId: string | null;
26	  sourceConclusionId: string | null;
27	  patternType: string;
28	  title: string;
29	  summary: string;
30	  reasoningMoves: unknown;
31	  transferTargets: unknown;
32	  assumptions: unknown;
33	  failureModes: unknown;
34	  evidenceAnchors: unknown;
35	  confidence: number | string;
36	};
37	
38	const MAX_PROFILE_COUNT = 8;
39	const MAX_LIST_ITEMS = 12;
40	
41	function cleanString(value: unknown, maxLength: number): string {
42	  if (typeof value !== "string") return "";
43	  return value.replace(/[\u0000-\u0008\u000b\u000c\u000e-\u001f\ufeff]/g, "").trim().slice(0, maxLength);
44	}
45	
46	function stringArray(value: unknown): string[] {
47	  if (!Array.isArray(value)) return [];
48	  return value
49	    .map((item) => cleanString(item, 600))
50	    .filter(Boolean)
51	    .slice(0, MAX_LIST_ITEMS);
52	}
53	
54	function confidenceValue(value: unknown): number {
55	  const n = typeof value === "number" ? value : Number(value || 0.5);
56	  if (!Number.isFinite(n)) return 0.5;
57	  return Math.min(1, Math.max(0, n));
58	}
59	
60	function anchorArray(value: unknown): PublicationMethodologyProfile["evidenceAnchors"] {
61	  if (!Array.isArray(value)) return [];
62	  // Evidence anchors are allowed to preserve public-safe provenance metadata,
63	  // but never the underlying transcript quote text.
64	  return value.flatMap((item): PublicationMethodologyProfile["evidenceAnchors"] => {
65	    if (!item || typeof item !== "object" || Array.isArray(item)) return [];
66	    const raw = item as Record<string, unknown>;
67	    const sentenceIndex =
68	      typeof raw.sentenceIndex === "number" && Number.isFinite(raw.sentenceIndex) && raw.sentenceIndex >= 0
69	        ? Math.trunc(raw.sentenceIndex)
70	        : undefined;
71	    const sourceTitle = cleanString(raw.sourceTitle, 180);
72	    if (sentenceIndex === undefined && !sourceTitle) return [];
73	    return [{ ...(sentenceIndex !== undefined ? { sentenceIndex } : {}), ...(sourceTitle ? { sourceTitle } : {}) }];
74	  }).slice(0, MAX_LIST_ITEMS);
75	}
76	
77	export function normalizeMethodologyProfiles(value: unknown): PublicationMethodologyProfile[] {
78	  if (!Array.isArray(value)) return [];
79	  return value.flatMap((item): PublicationMethodologyProfile[] => {
80	    if (!item || typeof item !== "object" || Array.isArray(item)) return [];
81	    const raw = item as Record<string, unknown>;
82	    const title = cleanString(raw.title, 180);
83	    const summary = cleanString(raw.summary, 4_000);
84	    if (!title || !summary) return [];
85	    return [
86	      {
87	        patternType: cleanString(raw.patternType, 80) || "manual_methodology",
88	        title,
89	        summary,
90	        reasoningMoves: stringArray(raw.reasoningMoves),
91	        transferTargets: stringArray(raw.transferTargets),
92	        assumptions: stringArray(raw.assumptions),
93	        failureModes: stringArray(raw.failureModes),
94	        evidenceAnchors: anchorArray(raw.evidenceAnchors),
95	        confidence: confidenceValue(raw.confidence),
96	      },
97	    ];
98	  }).slice(0, MAX_PROFILE_COUNT);
99	}
100	
101	export function parseMethodologyPayload(value: unknown): PublicationMethodology {
102	  if (!value || typeof value !== "object" || Array.isArray(value)) {
103	    return { schema: "theseus.methodology.v1", reviewerNarrative: "", profiles: [] };
104	  }
105	  const raw = value as Record<string, unknown>;
106	  return {
107	    schema: "theseus.methodology.v1",
108	    reviewerNarrative: cleanString(raw.reviewerNarrative, 4_000),
109	    profiles: normalizeMethodologyProfiles(raw.profiles),
110	  };
111	}
112	
113	export function hasMethodologyContent(methodology: PublicationMethodology): boolean {
114	  return methodology.profiles.length > 0 || methodology.reviewerNarrative.trim().length > 0;
115	}
116	
117	function rowToProfile(row: MethodologyProfileRow): PublicationMethodologyProfile {
118	  return {
119	    patternType: cleanString(row.patternType, 80) || "manual_methodology",
120	    title: cleanString(row.title, 180),
121	    summary: cleanString(row.summary, 4_000),
122	    reasoningMoves: stringArray(row.reasoningMoves),
123	    transferTargets: stringArray(row.transferTargets),
124	    assumptions: stringArray(row.assumptions),
125	    failureModes: stringArray(row.failureModes),
126	    evidenceAnchors: anchorArray(row.evidenceAnchors),
127	    confidence: confidenceValue(row.confidence),
128	  };
129	}
130	
131	function hasDisplayableProfile(profile: PublicationMethodologyProfile): boolean {
132	  return Boolean(profile.title && profile.summary);
133	}
134	
135	export async function profilesForConclusions(
136	  organizationId: string,
137	  conclusionIds: string[],
138	): Promise<Map<string, PublicationMethodologyProfile[]>> {
139	  const ids = [...new Set(conclusionIds.filter(Boolean))];
140	  const out = new Map<string, PublicationMethodologyProfile[]>();
141	  if (ids.length === 0) return out;
142	
143	  try {
144	    const rows = await db.$queryRaw<MethodologyProfileRow[]>`
145	      SELECT
146	        mp.id,
147	        mp."conclusionId",
148	        cs."conclusionId" AS "sourceConclusionId",
149	        mp."patternType",
150	        mp.title,
151	        mp.summary,
152	        mp."reasoningMoves",
153	        mp."transferTargets",
154	        mp.assumptions,
155	        mp."failureModes",
156	        mp."evidenceAnchors",
157	        mp.confidence
158	      FROM "MethodologyProfile" mp
159	      LEFT JOIN "ConclusionSource" cs ON cs."uploadId" = mp."uploadId"
160	      WHERE mp."organizationId" = ${organizationId}
161	        AND (
162	          mp."conclusionId" IN (${Prisma.join(ids)})
163	          OR cs."conclusionId" IN (${Prisma.join(ids)})
164	        )
165	      ORDER BY mp.confidence DESC, mp."createdAt" DESC
166	      LIMIT 200
167	    `;
168	    for (const row of rows) {
169	      const targets = [row.conclusionId, row.sourceConclusionId].filter((id): id is string => Boolean(id));
170	      const profile = rowToProfile(row);
171	      if (!hasDisplayableProfile(profile)) continue;
172	      for (const id of targets) {
173	        if (!ids.includes(id)) continue;
174	        const list = out.get(id) ?? [];
175	        if (!list.some((profile) => profile.patternType === row.patternType)) {
176	          list.push(profile);
177	        }
178	        out.set(id, list.slice(0, 6));
179	      }
180	    }
181	  } catch (error) {
182	    console.error("[methodology] profile query failed (schema lag?):", error);
183	  }
184	
185	  return out;
186	}
187	
188	export type MqsSubScore = {
189	  score: number;
190	  evidence: Record<string, unknown>;
191	};
192	
193	export type MqsRecord = {
194	  conclusionId: string;
195	  progressivity: number;
196	  severity: number;
197	  aimMethodFit: number;
198	  compressibility: number;
199	  domainSensitivity: number;
200	  composite: number;
201	  evidence: Record<string, unknown>;
202	  modelName: string;
203	  promptVersion: string;
204	  scoredAt: string;
205	};
206	
207	type MqsRow = {
208	  conclusionId: string;
209	  progressivity: number | string;
210	  severity: number | string;
211	  aimMethodFit: number | string;
212	  compressibility: number | string;
213	  domainSensitivity: number | string;
214	  composite: number | string;
215	  evidence: unknown;
216	  modelName: string;
217	  promptVersion: string;
218	  scoredAt: Date | string;
219	};
220	
221	function num01(value: unknown): number {
222	  const n = typeof value === "number" ? value : Number(value || 0);
223	  if (!Number.isFinite(n)) return 0;
224	  return Math.min(1, Math.max(0, n));
225	}
226	
227	function evidenceObject(value: unknown): Record<string, unknown> {
228	  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
229	  return value as Record<string, unknown>;
230	}
231	
232	function isoDate(value: Date | string): string {
233	  return value instanceof Date ? value.toISOString() : String(value);
234	}
235	
236	function rowToMqs(row: MqsRow): MqsRecord {
237	  return {
238	    conclusionId: row.conclusionId,
239	    progressivity: num01(row.progressivity),
240	    severity: num01(row.severity),
241	    aimMethodFit: num01(row.aimMethodFit),
242	    compressibility: num01(row.compressibility),
243	    domainSensitivity: num01(row.domainSensitivity),
244	    composite: num01(row.composite),
245	    evidence: evidenceObject(row.evidence),
246	    modelName: cleanString(row.modelName, 120) || "stub",
247	    promptVersion: cleanString(row.promptVersion, 120) || "mqs-prompt-v1.0",
248	    scoredAt: isoDate(row.scoredAt),
249	  };
250	}
251	
252	export async function mqsForConclusion(
253	  organizationId: string,
254	  conclusionId: string,
255	): Promise<MqsRecord | null> {
256	  try {
257	    const rows = await db.$queryRaw<MqsRow[]>`
258	      SELECT
259	        "conclusionId",
260	        progressivity,
261	        severity,
262	        "aimMethodFit",
263	        compressibility,
264	        "domainSensitivity",
265	        composite,
266	        evidence,
267	        "modelName",
268	        "promptVersion",
269	        "scoredAt"
270	      FROM "MethodologyQualityScore"
271	      WHERE "organizationId" = ${organizationId}
272	        AND "conclusionId" = ${conclusionId}
273	      LIMIT 1
274	    `;
275	    return rows[0] ? rowToMqs(rows[0]) : null;
276	  } catch (error) {
277	    console.error("[mqs] fetch failed (schema lag?):", error);
278	    return null;
279	  }
280	}
281	
282	/**
283	 * Public-side filter: only return an MQS record when the score is fresher
284	 * than the conclusion's last edit. The public pill is hidden otherwise.
285	 */
286	export function isMqsFreshForPublic(
287	  mqs: MqsRecord | null,
288	  conclusionUpdatedAt: Date | string | null | undefined,
289	): boolean {
290	  if (!mqs) return false;
291	  if (!conclusionUpdatedAt) return true;
292	  const scored = new Date(mqs.scoredAt).getTime();
293	  const edited = new Date(isoDate(conclusionUpdatedAt as Date | string)).getTime();
294	  if (!Number.isFinite(scored) || !Number.isFinite(edited)) return false;
295	  return scored >= edited;
296	}
297	
298	export async function profilesForUpload(
299	  organizationId: string,
300	  uploadId: string,
301	): Promise<PublicationMethodologyProfile[]> {
302	  try {
303	    const rows = await db.$queryRaw<MethodologyProfileRow[]>`
304	      SELECT
305	        id,
306	        "conclusionId",
307	        NULL AS "sourceConclusionId",
308	        "patternType",
309	        title,
310	        summary,
311	        "reasoningMoves",
312	        "transferTargets",
313	        assumptions,
314	        "failureModes",
315	        "evidenceAnchors",
316	        confidence
317	      FROM "MethodologyProfile"
318	      WHERE "organizationId" = ${organizationId}
319	        AND "uploadId" = ${uploadId}
320	      ORDER BY confidence DESC, "createdAt" DESC
321	      LIMIT 8
322	    `;
323	    return rows.map(rowToProfile).filter(hasDisplayableProfile);
324	  } catch (error) {
325	    console.error("[methodology] upload profile query failed (schema lag?):", error);
326	    return [];
327	  }
328	}
