1	import { db } from "@/lib/db";
2	
3	/**
4	 * Per-method track-record surface, materialized by `noosphere methods
5	 * track-record --rebuild` into the `MethodTrackRecord` table. The Python
6	 * aggregator owns every numerical decision (weighted Brier, OLS slope,
7	 * bootstrap CI); this TS lib is read-only — it normalizes Prisma rows
8	 * and exposes the publish gate.
9	 *
10	 * Sample-size publish gate: `MIN_PUBLISHABLE_SAMPLE = 5`. The public
11	 * `/methodology/[method]/track-record` page uses
12	 * `isPubliclyPublishable()` as a hard filter — methods below the
13	 * threshold do not get a public page.
14	 */
15	export const MIN_PUBLISHABLE_SAMPLE = 5;
16	
17	export type MethodTrackRecordRow = {
18	  organizationId: string;
19	  methodName: string;
20	  methodVersion: string;
21	  domain: string;
22	  sampleSize: number;
23	  weightedBrier: number | null;
24	  calibrationSlope: number | null;
25	  calibrationSlopeCiLow: number | null;
26	  calibrationSlopeCiHigh: number | null;
27	  severityPassRate: number | null;
28	  computedAt: Date;
29	};
30	
31	function decimalToNumber(value: unknown): number | null {
32	  if (value === null || value === undefined) return null;
33	  if (typeof value === "number") return Number.isFinite(value) ? value : null;
34	  if (typeof value === "string") {
35	    const n = Number(value);
36	    return Number.isFinite(n) ? n : null;
37	  }
38	  if (typeof value === "object" && "toNumber" in (value as object)) {
39	    try {
40	      const n = (value as { toNumber: () => number }).toNumber();
41	      return Number.isFinite(n) ? n : null;
42	    } catch {
43	      return null;
44	    }
45	  }
46	  return null;
47	}
48	
49	function normalizeRow(raw: {
50	  organizationId: string;
51	  methodName: string;
52	  methodVersion: string;
53	  domain: string;
54	  sampleSize: number;
55	  weightedBrier: unknown;
56	  calibrationSlope: unknown;
57	  calibrationSlopeCiLow: unknown;
58	  calibrationSlopeCiHigh: unknown;
59	  severityPassRate: unknown;
60	  computedAt: Date;
61	}): MethodTrackRecordRow {
62	  return {
63	    organizationId: raw.organizationId,
64	    methodName: raw.methodName,
65	    methodVersion: raw.methodVersion,
66	    domain: raw.domain,
67	    sampleSize: raw.sampleSize,
68	    weightedBrier: decimalToNumber(raw.weightedBrier),
69	    calibrationSlope: decimalToNumber(raw.calibrationSlope),
70	    calibrationSlopeCiLow: decimalToNumber(raw.calibrationSlopeCiLow),
71	    calibrationSlopeCiHigh: decimalToNumber(raw.calibrationSlopeCiHigh),
72	    severityPassRate: decimalToNumber(raw.severityPassRate),
73	    computedAt: raw.computedAt,
74	  };
75	}
76	
77	/** All track-record rows for a (method, version) across every domain
78	 *  in the given org. Caller is expected to pre-filter by org so we don't
79	 *  leak another tenant's rows through the public route by accident. */
80	export async function fetchTrackRecordsForMethod(
81	  organizationId: string,
82	  methodName: string,
