  | "composition"
  | "failures"
  | "conclusions";

const TABS: Array<{ key: MethodTabKey; label: string; suffix: string }> = [
  { key: "overview", label: "Overview", suffix: "" },
  { key: "track-record", label: "Track record", suffix: "/track-record" },
  { key: "domain", label: "Domain", suffix: "/domain" },
  { key: "composition", label: "Composition", suffix: "/composition" },
  { key: "failures", label: "Failure modes", suffix: "/failures" },
  { key: "conclusions", label: "Conclusions", suffix: "/conclusions" },
];

/**
 * URL-driven tab strip for `/methodology/[method]/...`. Each tab is a
 * distinct route so server rendering keeps every tab independently
 * shareable and indexable. Rendered as a `<nav role="tablist">` so the
 * accessibility tree matches the visual treatment.
 */
export default function MethodTabs({
  method,
  active,
}: {
  method: string;
  active: MethodTabKey;
}) {
  const enc = encodeURIComponent(method);
  return (
    <nav
      role="tablist"
      aria-label={`Sections for method ${method}`}
      style={{
        display: "flex",
        flexWrap: "wrap",
        gap: 0,
        margin: "1rem 0 1.5rem",
        borderBottom: "1px solid var(--public-rule, #ddd)",
      }}
    >
      {TABS.map((t) => {
        const isActive = t.key === active;
        const href = `/methodology/${enc}${t.suffix}`;
